import{f as l,D as A,o as r,c as E,a2 as e,b as d,w as o,a,G as n,a5 as i}from"./chunks/framework.Ccw_j35p.js";const p=JSON.parse('{"title":"高并发场景下的网络安全","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/security/network-security.md","filePath":"high-concurrency/security/network-security.md","lastUpdated":1780917874000}'),S={name:"high-concurrency/security/network-security.md"};function g(B,t,h,T,C,u){const s=A("Mermaid");return r(),E("div",null,[t[4]||(t[4]=e('<h1 id="高并发场景下的网络安全" tabindex="-1">高并发场景下的网络安全 <a class="header-anchor" href="#高并发场景下的网络安全" aria-label="Permalink to &quot;高并发场景下的网络安全&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>高并发系统不仅要能&quot;扛住&quot;正常流量，还要能&quot;防住&quot;恶意流量。安全防护是架构设计中不可忽视的一环，尤其在面对 DDoS、CC 攻击时，安全策略直接决定了系统能否正常服务。</p><div class="danger custom-block"><p class="custom-block-title">关键认知</p><p>安全不是&quot;加个防火墙就完事了&quot;，而是<strong>纵深防御</strong>：网络层 → 应用层 → 业务层逐层设防。</p></div><h2 id="一、ddos-攻击与防护" tabindex="-1">一、DDoS 攻击与防护 <a class="header-anchor" href="#一、ddos-攻击与防护" aria-label="Permalink to &quot;一、DDoS 攻击与防护&quot;">​</a></h2><h3 id="_1-1-常见-ddos-攻击类型" tabindex="-1">1.1 常见 DDoS 攻击类型 <a class="header-anchor" href="#_1-1-常见-ddos-攻击类型" aria-label="Permalink to &quot;1.1 常见 DDoS 攻击类型&quot;">​</a></h3>',6)),(r(),d(i,null,{default:o(()=>[n(s,{id:"mermaid-20",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20DDoS%5B%22DDoS%20%E6%94%BB%E5%87%BB%E5%88%86%E7%B1%BB%22%5D%20--%3E%20L3%5B%22%E7%BD%91%E7%BB%9C%E5%B1%82%E6%94%BB%E5%87%BB%22%5D%0A%20%20%20%20DDoS%20--%3E%20L4%5B%22%E4%BC%A0%E8%BE%93%E5%B1%82%E6%94%BB%E5%87%BB%22%5D%0A%20%20%20%20DDoS%20--%3E%20L7%5B%22%E5%BA%94%E7%94%A8%E5%B1%82%E6%94%BB%E5%87%BB%22%5D%0A%20%20%20%20%0A%20%20%20%20L3%20--%3E%20L3A%5B%22ICMP%20Flood%22%5D%0A%20%20%20%20L3%20--%3E%20L3B%5B%22DNS%20%E5%8F%8D%E5%B0%84%E6%94%BE%E5%A4%A7%22%5D%0A%20%20%20%20%0A%20%20%20%20L4%20--%3E%20L4A%5B%22SYN%20Flood%3Cbr%2F%3E%E5%8D%8A%E8%BF%9E%E6%8E%A5%E8%80%97%E5%B0%BD%22%5D%0A%20%20%20%20L4%20--%3E%20L4B%5B%22UDP%20Flood%3Cbr%2F%3E%E5%B8%A6%E5%AE%BD%E6%89%93%E6%BB%A1%22%5D%0A%20%20%20%20%0A%20%20%20%20L7%20--%3E%20L7A%5B%22HTTP%20Flood%3Cbr%2F%3ECC%20%E6%94%BB%E5%87%BB%22%5D%0A%20%20%20%20L7%20--%3E%20L7B%5B%22Slowloris%3Cbr%2F%3E%E6%85%A2%E9%80%9F%E8%BF%9E%E6%8E%A5%E8%80%97%E5%B0%BD%22%5D%0A%20%20%20%20%0A%20%20%20%20style%20DDoS%20fill%3A%23fef2f2%2Cstroke%3A%23dc2626%2Ccolor%3A%23991b1b%0A%20%20%20%20style%20L3%20fill%3A%23fef3c7%2Cstroke%3A%23d97706%2Ccolor%3A%2392400e%0A%20%20%20%20style%20L4%20fill%3A%23fce7f3%2Cstroke%3A%23db2777%2Ccolor%3A%239d174d%0A%20%20%20%20style%20L7%20fill%3A%23dbeafe%2Cstroke%3A%232563eb%2Ccolor%3A%231e40af%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[a(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=e('<table tabindex="0"><thead><tr><th>攻击类型</th><th>原理</th><th>防御手段</th></tr></thead><tbody><tr><td><strong>SYN Flood</strong></td><td>伪造大量 SYN 包，耗尽服务端 SYN 队列</td><td>SYN Cookie、SYN Proxy、连接限速</td></tr><tr><td><strong>UDP Flood</strong></td><td>大量 UDP 包占满带宽</td><td>流量清洗、黑洞路由</td></tr><tr><td><strong>DNS 反射放大</strong></td><td>伪造源 IP 向 DNS 服务器查询，响应放大到目标</td><td>源 IP 验证、限速</td></tr><tr><td><strong>HTTP Flood（CC）</strong></td><td>大量 HTTP 请求耗尽应用资源</td><td>WAF、频率限制、验证码</td></tr><tr><td><strong>Slowloris</strong></td><td>慢速发送 HTTP 请求，占用连接不释放</td><td>连接超时、最大连接数限制</td></tr></tbody></table><h3 id="_1-2-ddos-防护架构" tabindex="-1">1.2 DDoS 防护架构 <a class="header-anchor" href="#_1-2-ddos-防护架构" aria-label="Permalink to &quot;1.2 DDoS 防护架构&quot;">​</a></h3>',2)),(r(),d(i,null,{default:o(()=>[n(s,{id:"mermaid-96",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22%E6%AD%A3%E5%B8%B8%E6%B5%81%E9%87%8F%22%5D%20--%3E%20B%5B%22%E6%B5%81%E9%87%8F%E6%B8%85%E6%B4%97%E4%B8%AD%E5%BF%83%22%5D%0A%20%20%20%20C%5B%22%E6%94%BB%E5%87%BB%E6%B5%81%E9%87%8F%22%5D%20--%3E%20B%0A%20%20%20%20B%20--%3E%20D%7B%22%E6%B5%81%E9%87%8F%E5%88%86%E6%9E%90%22%7D%0A%20%20%20%20D%20--%3E%7C%22%E6%AD%A3%E5%B8%B8%22%7C%20E%5B%22%E6%BA%90%E7%AB%99%22%5D%0A%20%20%20%20D%20--%3E%7C%22%E6%94%BB%E5%87%BB%22%7C%20F%5B%22%E9%BB%91%E6%B4%9E%2F%E4%B8%A2%E5%BC%83%22%5D%0A%20%20%20%20%0A%20%20%20%20style%20B%20fill%3A%23dbeafe%2Cstroke%3A%232563eb%2Ccolor%3A%231e40af%0A%20%20%20%20style%20F%20fill%3A%23fef2f2%2Cstroke%3A%23dc2626%2Ccolor%3A%23991b1b%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[a(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=e('<p><strong>防护层次：</strong></p><ol><li><strong>运营商层级</strong>：Anycast 分散流量到全球节点，近源清洗</li><li><strong>CDN 层级</strong>：利用 CDN 的带宽和节点分散攻击流量</li><li><strong>高防 IP</strong>：专业 DDoS 清洗服务，如阿里云高防、腾讯云大禹</li><li><strong>应用层级</strong>：WAF + 限流 + 验证码</li></ol><hr><h2 id="二、waf-web-应用防火墙" tabindex="-1">二、WAF（Web 应用防火墙） <a class="header-anchor" href="#二、waf-web-应用防火墙" aria-label="Permalink to &quot;二、WAF（Web 应用防火墙）&quot;">​</a></h2><h3 id="_2-1-waf-核心原理" tabindex="-1">2.1 WAF 核心原理 <a class="header-anchor" href="#_2-1-waf-核心原理" aria-label="Permalink to &quot;2.1 WAF 核心原理&quot;">​</a></h3><p>WAF 工作在应用层（HTTP/HTTPS），通过分析 HTTP 请求内容来识别和拦截攻击。</p><table tabindex="0"><thead><tr><th>检测方式</th><th>原理</th><th>优缺点</th></tr></thead><tbody><tr><td><strong>规则引擎</strong></td><td>基于正则匹配已知攻击模式（SQL 注入、XSS）</td><td>准确但需维护规则库</td></tr><tr><td><strong>语义分析</strong></td><td>解析 SQL/JS 语法，判断是否恶意</td><td>准确率高，误报低</td></tr><tr><td><strong>机器学习</strong></td><td>基于历史数据训练模型</td><td>可检测未知攻击，但误报率较高</td></tr><tr><td><strong>RASP</strong></td><td>嵌入应用运行时，监控执行逻辑</td><td>精准但侵入性强</td></tr></tbody></table><h3 id="_2-2-cc-攻击-vs-限流" tabindex="-1">2.2 CC 攻击 vs 限流 <a class="header-anchor" href="#_2-2-cc-攻击-vs-限流" aria-label="Permalink to &quot;2.2 CC 攻击 vs 限流&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>CC 攻击</th><th>正常限流场景</th></tr></thead><tbody><tr><td><strong>目的</strong></td><td>恶意耗尽资源，让服务不可用</td><td>保护系统不被突发流量打垮</td></tr><tr><td><strong>流量特征</strong></td><td>请求简单，消耗资源少但频率极高</td><td>正常的业务请求，只是量大</td></tr><tr><td><strong>防护手段</strong></td><td>WAF + 验证码 + IP 黑名单</td><td>令牌桶/漏桶限流</td></tr><tr><td><strong>关键区别</strong></td><td>CC 攻击会绕过 CDN 缓存直接打到源站</td><td>限流是保护机制，不是攻击</td></tr></tbody></table><hr><h2 id="三、https-tls-优化" tabindex="-1">三、HTTPS / TLS 优化 <a class="header-anchor" href="#三、https-tls-优化" aria-label="Permalink to &quot;三、HTTPS / TLS 优化&quot;">​</a></h2><h3 id="_3-1-tls-握手过程" tabindex="-1">3.1 TLS 握手过程 <a class="header-anchor" href="#_3-1-tls-握手过程" aria-label="Permalink to &quot;3.1 TLS 握手过程&quot;">​</a></h3>',12)),(r(),d(i,null,{default:o(()=>[n(s,{id:"mermaid-264",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20C%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20%20%20participant%20S%20as%20%E6%9C%8D%E5%8A%A1%E7%AB%AF%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20TLS%201.2%20%E6%8F%A1%E6%89%8B%EF%BC%882-RTT%EF%BC%89%0A%20%20%20%20C-%3E%3ES%3A%20ClientHello%EF%BC%88%E6%94%AF%E6%8C%81%E7%9A%84%E5%8A%A0%E5%AF%86%E5%A5%97%E4%BB%B6%EF%BC%89%0A%20%20%20%20S-%3E%3EC%3A%20ServerHello%20%2B%20%E8%AF%81%E4%B9%A6%20%2B%20ServerKeyExchange%0A%20%20%20%20C-%3E%3EC%3A%20%E9%AA%8C%E8%AF%81%E8%AF%81%E4%B9%A6%0A%20%20%20%20C-%3E%3ES%3A%20ClientKeyExchange%20%2B%20ChangeCipherSpec%0A%20%20%20%20S-%3E%3EC%3A%20ChangeCipherSpec%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E6%8F%A1%E6%89%8B%E5%AE%8C%E6%88%90%EF%BC%8C%E5%BC%80%E5%A7%8B%E5%8A%A0%E5%AF%86%E9%80%9A%E4%BF%A1%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20TLS%201.3%20%E6%8F%A1%E6%89%8B%EF%BC%881-RTT%EF%BC%89%0A%20%20%20%20C-%3E%3ES%3A%20ClientHello%EF%BC%88%E6%94%AF%E6%8C%81%E7%9A%84%E5%8A%A0%E5%AF%86%E5%A5%97%E4%BB%B6%20%2B%20%E5%AF%86%E9%92%A5%E5%8D%8F%E5%95%86%E5%8F%82%E6%95%B0%EF%BC%89%0A%20%20%20%20S-%3E%3EC%3A%20ServerHello%20%2B%20%E8%AF%81%E4%B9%A6%20%2B%20%E5%8A%A0%E5%AF%86%E6%89%A9%E5%B1%95%20%2B%20Finished%0A%20%20%20%20C-%3E%3ES%3A%20Finished%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E6%8F%A1%E6%89%8B%E5%AE%8C%E6%88%90%EF%BC%8C%E5%87%8F%E5%B0%91%E4%BA%86%201%20%E4%B8%AA%20RTT%0A"})]),fallback:o(()=>[...t[2]||(t[2]=[a(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=e('<h3 id="_3-2-tls-优化策略" tabindex="-1">3.2 TLS 优化策略 <a class="header-anchor" href="#_3-2-tls-优化策略" aria-label="Permalink to &quot;3.2 TLS 优化策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优化手段</th><th>原理</th><th>效果</th></tr></thead><tbody><tr><td><strong>TLS 1.3</strong></td><td>减少握手 RTT（2→1），移除不安全加密算法</td><td>减少 1 个 RTT</td></tr><tr><td><strong>Session 复用</strong></td><td>客户端缓存 Session ID/Ticket，下次连接跳过完整握手</td><td>0-RTT 恢复</td></tr><tr><td><strong>OCSP Stapling</strong></td><td>服务端主动获取 OCSP 响应并附带在握手中</td><td>省去客户端查询证书状态</td></tr><tr><td><strong>False Start</strong></td><td>客户端在收到 Finished 前就开始发送数据</td><td>减少等待时间</td></tr><tr><td><strong>证书链优化</strong></td><td>精简证书链，减少传输大小</td><td>减少握手数据量</td></tr><tr><td><strong>HTTP/2 多路复用</strong></td><td>一个连接承载多个请求</td><td>减少 TLS 握手次数</td></tr></tbody></table><h3 id="_3-3-session-复用" tabindex="-1">3.3 Session 复用 <a class="header-anchor" href="#_3-3-session-复用" aria-label="Permalink to &quot;3.3 Session 复用&quot;">​</a></h3>',3)),(r(),d(i,null,{default:o(()=>[n(s,{id:"mermaid-354",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20C%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20%20%20participant%20S%20as%20%E6%9C%8D%E5%8A%A1%E7%AB%AF%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E9%A6%96%E6%AC%A1%E5%AE%8C%E6%95%B4%E6%8F%A1%E6%89%8B%0A%20%20%20%20C-%3E%3ES%3A%20ClientHello%0A%20%20%20%20S-%3E%3EC%3A%20ServerHello%20%2B%20%E8%AF%81%E4%B9%A6%20%2B%20Session%20Ticket%0A%20%20%20%20Note%20over%20C%3A%20%E7%BC%93%E5%AD%98%20Session%20Ticket%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E5%90%8E%E7%BB%AD%20Session%20%E5%A4%8D%E7%94%A8%0A%20%20%20%20C-%3E%3ES%3A%20ClientHello%20%2B%20Session%20Ticket%0A%20%20%20%20S-%3E%3ES%3A%20%E8%A7%A3%E5%AF%86%20Session%20Ticket%EF%BC%8C%E6%81%A2%E5%A4%8D%E4%BC%9A%E8%AF%9D%0A%20%20%20%20S-%3E%3EC%3A%20ServerHello%20%2B%20Finished%EF%BC%880-RTT%EF%BC%89%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E8%B7%B3%E8%BF%87%E8%AF%81%E4%B9%A6%E9%AA%8C%E8%AF%81%E5%92%8C%E5%AF%86%E9%92%A5%E4%BA%A4%E6%8D%A2%0A"})]),fallback:o(()=>[...t[3]||(t[3]=[a(" Loading... ",-1)])]),_:1})),t[8]||(t[8]=e('<hr><h2 id="四、api-安全" tabindex="-1">四、API 安全 <a class="header-anchor" href="#四、api-安全" aria-label="Permalink to &quot;四、API 安全&quot;">​</a></h2><table tabindex="0"><thead><tr><th>安全措施</th><th>实现方式</th><th>防护目标</th></tr></thead><tbody><tr><td><strong>签名校验</strong></td><td>HMAC-SHA256 对请求参数签名</td><td>防篡改</td></tr><tr><td><strong>Anti-Replay</strong></td><td>请求携带 Timestamp + Nonce，服务端校验</td><td>防重放攻击</td></tr><tr><td><strong>参数校验</strong></td><td>输入长度/类型/范围校验</td><td>防注入</td></tr><tr><td><strong>频率限制</strong></td><td>基于 IP/用户/API Key 的令牌桶限流</td><td>防刷</td></tr><tr><td><strong>HTTPS 强制</strong></td><td>全站 HTTPS，HSTS 头</td><td>防中间人攻击</td></tr></tbody></table><hr><h2 id="面试题" tabindex="-1">面试题 <a class="header-anchor" href="#面试题" aria-label="Permalink to &quot;面试题&quot;">​</a></h2><h3 id="_1-syn-flood-攻击原理和防护方法" tabindex="-1">1. SYN Flood 攻击原理和防护方法？ <a class="header-anchor" href="#_1-syn-flood-攻击原理和防护方法" aria-label="Permalink to &quot;1. SYN Flood 攻击原理和防护方法？&quot;">​</a></h3><p><strong>知识要点：</strong> 攻击者伪造IP发送大量SYN不回复ACK，占满服务端SYN队列，正常请求无法建立连接。</p><p><strong>我们被SYN Flood攻击过一次，而且是&quot;误伤&quot;。</strong> 一个大客户做活动，他们的客户端因为一个SDK bug在短时间内发起了大量TCP连接，每个连接都是正常的三次握手——但量太大（峰值约8万QPS），服务端SYN队列被打满，合法用户完全连不上来。</p><p><strong>踩坑经历：</strong> 起初运维把<code>tcp_max_syn_backlog</code>从默认的1024调到了65535，确实扛住了更多SYN包，但系统内存被大量半连接占满。最终方案是开启SYN Cookie（<code>net.ipv4.tcp_syncookies=1</code>），服务端收到SYN后不分配资源，而是把连接信息加密后作为Cookie返回给客户端，客户端ACK时带回Cookie验证通过才分配资源。效果立竿见影。</p><p><strong>量化结果：</strong> 开启SYN Cookie后，相同8万SYN QPS下内存占用从1.2GB降到200MB，正常用户的连接建立成功率从45%恢复到98%。TCP连接队列溢出导致的丢包从每秒3000+降到零。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;SYN Cookie有什么副作用？不能支持TCP窗口缩放吗？&quot; —— 确实不能支持全部TCP选项（如大窗口Scale和SACK）。Cookie只有32位，只能编码基本的MSS和少量选项。所以SYN Cookie是&quot;应急手段&quot;不是&quot;日常方案&quot;——攻击时开启，平常关掉。</li><li><strong>追问2：</strong> &quot;SYN Proxy和SYN Cookie有什么区别？&quot; —— SYN Proxy是&quot;中间人&quot;：Proxy替服务端完成三次握手，握手成功后再把连接转发给后端。好处是后端完全无感，坏处是多了一跳+Proxy自己可能成为瓶颈。大厂一般用硬件设备（如F5）做SYN Proxy。</li></ul><h3 id="_2-ddos-流量清洗怎么做" tabindex="-1">2. DDoS 流量清洗怎么做？ <a class="header-anchor" href="#_2-ddos-流量清洗怎么做" aria-label="Permalink to &quot;2. DDoS 流量清洗怎么做？&quot;">​</a></h3><p><strong>知识要点：</strong> 流量牵引→分析→清洗→回注，配合Anycast全球分散和近源清洗。</p><p><strong>我们经历过一次&quot;不专业的流量清洗&quot;。</strong> 用的是阿里云高防IP，结果高防的阈值设太高了（10Gbps），一个500Mbps的CC攻击穿过高防直接打到了源站——因为高防以为这是正常流量波动。源站Nginx差点打挂。</p><p><strong>踩坑经历：</strong> 重新调整阈值后采用了&quot;自适应清洗&quot;——不是固定阈值，而是基于过去24小时的流量基线和同比（上周同一时间的流量），超出基线200%才触发清洗。但自适应带来了新问题：日常流量高峰期和低峰期基线差异大，需要分时段设置基线。</p><p><strong>量化结果：</strong> 自适应清洗上线后，DDoS误判率从15%降到3%，同时攻击漏判率从8%降到2%。一次真实的800Mbps CC攻击被成功拦截在清洗中心，源站流量没受到任何冲击。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;清洗会不会把正常流量也洗掉？&quot; —— 会，这是一个trade-off。如果清洗策略太激进（如针对某个国家的流量全部清洗），会误杀正常用户。我们的做法是&quot;分级清洗&quot;：明显攻击特征（如某个IP每秒1000+请求）直接黑名单；疑似攻击（如请求模式异常但频率不高）先人机验证（JS挑战）。</li><li><strong>追问2：</strong> &quot;自建清洗还是用云厂商的高防？&quot; —— 低于10Gbps的DDoS可以自建（iptables+ngx+lua），高于10Gbps必须用云厂商高防或运营商清洗。因为攻击流量超过你的带宽上限时，运营商入口就先把你&quot;黑洞&quot;了——就算你的设备能处理，带宽也被占满了。</li></ul><h3 id="_3-waf-和限流有什么区别" tabindex="-1">3. WAF 和限流有什么区别？ <a class="header-anchor" href="#_3-waf-和限流有什么区别" aria-label="Permalink to &quot;3. WAF 和限流有什么区别？&quot;">​</a></h3><p><strong>知识要点：</strong> WAF看请求内容（防注入/XSS），限流看请求频率（防过载），两者互补。</p><p><strong>我们用Nginx限流充当WAF，被安全团队指出来了。</strong> Nginx的<code>limit_req</code>只能按频率拦截，不能检测请求内容——一个恶意请求如果频率不高（如每分钟一次SQL注入），限流根本拦不住。后来加了一层ModSecurity WAF，Nginx在前做频率控制，ModSecurity在后做内容分析。</p><p><strong>量化结果：</strong> WAF上线后第一个月拦截了约1200次SQL注入尝试（大部分是自动化工具扫描）、约800次XSS尝试。平均每个被拦截请求的内容扫描耗时约3ms（ModSecurity基于正则匹配），对正常延迟影响不到2%。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;WAF规则太多会不会影响性能？&quot; —— 会。我们测试过：100条规则时ModSecurity延迟约2ms，500条规则时约8ms，1000条规则时约20ms。所以线上只开启&quot;高命中率规则&quot;（OWASP核心规则集的Top 100），其余的作为可选规则报警但不拦截。</li><li><strong>追问2：</strong> &quot;WAF误拦了正常业务怎么办？&quot; —— 我们每周有约2-3次误拦。处理机制：一是WAF规则加白名单（如特定URL不检测指定规则），二是拦截时返回可自定义的错误页并带上requestId，客服可以根据requestId查找拦截原因并加白名单。</li></ul><h3 id="_4-tls-1-3-相比-1-2-有什么优化" tabindex="-1">4. TLS 1.3 相比 1.2 有什么优化？ <a class="header-anchor" href="#_4-tls-1-3-相比-1-2-有什么优化" aria-label="Permalink to &quot;4. TLS 1.3 相比 1.2 有什么优化？&quot;">​</a></h3><p><strong>知识要点：</strong> 握手从2-RTT降到1-RTT（0-RTT恢复），移除RSA密钥交换等不安全算法。</p><p><strong>我们从TLS 1.2升级到1.3后，API网关的P99延迟下降了约30ms。</strong> 移动端用户（4G网络，RTT约50ms）受益最大——1.2握手需要先TCP三次握手（1 RTT）+TLS握手（2 RTT）=3 RTT=150ms，1.3只需要TCP(1 RTT)+TLS(1 RTT)=2 RTT=100ms，少了50ms（一个来回）。</p><p><strong>踩坑经历：</strong> 但升级过程中出现了一个兼容性问题——部分老旧的Android设备（Android 7以下）不支持TLS 1.3，连接直接失败。我们不得不保留TLS 1.2为fallback（Nginx配置<code>ssl_protocols TLSv1.2 TLSv1.3;</code>），让客户端和服务端在握手中协商选择。</p><p><strong>量化结果：</strong> TLS 1.3使新客户端连接建立延迟P50减少约30%（150ms→100ms），API网关CPU因简化加密套件降低约10%。首次访问用户（无Session复用）的页面加载时间减少约25%。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;0-RTT有什么安全风险？&quot; —— 0-RTT数据可能被重放攻击。攻击者截取0-RTT数据包后，可以重复发送给服务端，服务端会执行多次（如重复扣款）。解决方案是应用层做幂等性设计，或者对非幂等请求禁用0-RTT。</li><li><strong>追问2：</strong> &quot;TLS 1.3的0-RTT和Session Ticket的0-RTT一样吗？&quot; —— 本质一样。TLS 1.3的0-RTT依赖于PSK（Pre-Shared Key），Session Ticket机制是PSK的一种实现方式。不过1.3的0-RTT更标准化了。</li></ul><h3 id="_5-session-复用怎么减少握手开销" tabindex="-1">5. Session 复用怎么减少握手开销？ <a class="header-anchor" href="#_5-session-复用怎么减少握手开销" aria-label="Permalink to &quot;5. Session 复用怎么减少握手开销？&quot;">​</a></h3><p><strong>知识要点：</strong> Session ID/Ticket缓存会话状态，后续连接跳过完整握手，实现0-RTT。</p><p><strong>我们在API网关压测时发现Session Ticket复用率只有30%。</strong> 排查发现Nginx的<code>ssl_session_cache shared:SSL:10m</code>默认只存4000个Session，而我们的并发连接高峰超过2万，大量连接因为Session缓存满而走了完整握手。</p><p><strong>踩坑经历：</strong> 把缓存调到50m（可存约2万个Session），复用率涨到78%。但内存占用涨了约40MB——对于Nginx来说可以接受。另外发现一个业务细节：移动端的Session Ticket有效期受App切换到后台的影响——App进后台一段时间后系统可能清除网络状态，Ticket丢失，下次冷启动又走完整握手。</p><p><strong>量化结果：</strong> Session缓存调大后，API网关的TLS握手比例从70%降到22%，平均TLS延迟从120ms降到45ms。Nginx的CPU降低了约12%（省下的都是RSA/ECDSA密钥交换计算）。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;Session Ticket和Session ID哪个更好？&quot; —— Session Ticket不需要服务端存储（加密后发给客户端），更适合分布式环境。Session ID需要服务端共享Session存储（如Redis），增加了复杂度。Nginx默认用Ticket模式。</li><li><strong>追问2：</strong> &quot;如果Ticket的加密密钥泄露了怎么办？&quot; —— 所有用这个密钥加密的历史Ticket都可以被解密，攻击者可以解密过去的所有会话（前向安全性问题）。所以Nginx可以配定时轮换密钥（默认配置下Nginx重启时生成新密钥，但不停机也可以手动触发重载）。</li></ul><h3 id="_6-api-安全怎么防重放攻击" tabindex="-1">6. API 安全怎么防重放攻击？ <a class="header-anchor" href="#_6-api-安全怎么防重放攻击" aria-label="Permalink to &quot;6. API 安全怎么防重放攻击？&quot;">​</a></h3><p><strong>知识要点：</strong> Timestamp校验时间窗口，Nonce保证唯一性，签名防止篡改，timestamp+nonce+签名三重锁。</p><p><strong>我们做的API签名方案在灰度上线时被绕过了一次。</strong> 方案是请求参数+timestamp+nonce做签名，服务端验证签名+校验Nonce是否重复（存Redis防重）。结果压力测试发现Redis在5000 QPS下CPU飙到了40%——每个API请求都要Redis查一次Nonce是否存在。</p><p><strong>踩坑经历：</strong> 优化方案是在应用本地内存中用布隆过滤器先预判Nonce是否见过（大多数Nonce是新的，Bloom Filter直接通过），只有Bloom Filter判断&quot;可能存在&quot;时才查Redis。Bloom Filter误判率设0.1%导致Redis查询降到了原来的5%。但Bloom Filter会随Nonce数量增长越来越大，通过定期清理（每小时重建，连同过期的timestamp window一起清除）控制内存。</p><p><strong>量化结果：</strong> 防重放方案使Redis Nonce查询QPS从5000降到250，Redis CPU从40%降到5%。Bloom Filter内存占用约50MB（存储最近1小时的Nonce）。成功拦截过3次重放攻击尝试。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;时间窗口设多少合适？60秒太短用户时间不准怎么办？&quot; —— 我们设120秒，覆盖了99.9%设备的时钟偏差。同时客户端在发请求前先调用<code>/api/time</code>获取服务端时间进行校正（误差超过120秒的强制更新本地时钟）。差旅场景下确实会遇到用户手机时间不对的情况，我们做了error message提示&quot;您的设备时间与服务器时间偏差较大&quot;。</li><li><strong>追问2：</strong> &quot;如果攻击者在时间窗口内重放怎么办？&quot; —— 120秒窗口内Nonce查Redis防重，120秒后Nonce过期自动从Redis清理。攻击者在窗口内截获合法请求重放，如果Nonce已经用过了就会被拦截。</li></ul>',46))])}const b=l(S,[["render",g]]);export{p as __pageData,b as default};
